				dispatch.AssignsLen = bestPlacement.idx + 1
			}
			dispatch.Assigns[bestPlacement.idx].AddShip(shipID, ori, des)
			dispatch.Assigns[bestPlacement.idx].GenRoute()
		} else {
			inserted := false
			for i := 0; i < MAXASSIGNS; i++ {
				if i >= dispatch.AssignsLen {
					dispatch.AssignsLen = i + 1
				}
				ok := dispatch.Assigns[i].AddShip(shipID, ori, des)
				if ok {
					dispatch.Assigns[i].GenRoute()
					if dispatch.Assigns[i].Cost >= 0 {
						inserted = true
						break
					} else {
						dispatch.Assigns[i].RemoveShip(shipID)
						dispatch.Assigns[i].GenRoute()
					}
				}
				if i >= dispatch.AssignsLen && !ok {
					dispatch.AssignsLen--
				}
			}
			if !inserted {
				lastIdx := dispatch.AssignsLen
				if lastIdx < MAXASSIGNS {
					dispatch.Assigns[lastIdx].AddShip(shipID, ori, des)
					dispatch.Assigns[lastIdx].GenRoute()
					dispatch.AssignsLen++
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch
}
